const result = $input.first().json;
const exitCode = result.exitCode || 0;
const stdout = result.stdout || "";
const stderr = result.stderr || "";

const success = exitCode === 0;
const timestamp = new Date().toISOString();

const report = {
  timestamp: timestamp,
  job: "MC96 Daily Backup",
  success: success,
  exitCode: exitCode,
  output: stdout.substring(0, 2000),
  errors: stderr.substring(0, 1000),
  duration: result.executionTime || "unknown"
};

if (!success) {
  console.log("[BACKUP FAILED] MC96 backup failed at " + timestamp);
  console.log("Exit code: " + exitCode);
  console.log("Errors: " + stderr.substring(0, 500));
} else {
  console.log("[BACKUP OK] MC96 backup completed at " + timestamp);
}

return [{ json: report }];

const report = $input.first().json;
console.log("[MC96 BACKUP] SUCCESS at " + report.timestamp);
console.log("Output: " + report.output.substring(0, 500));
// Future: Write to D1 agent-memory as backup record
// Future: Send success notification to Slack #ops
return [{ json: { ...report, notified: false, channel: "#ops (pending Slack)" } }];

const report = $input.first().json;
console.log("[MC96 BACKUP] FAILURE at " + report.timestamp);
console.log("Exit code: " + report.exitCode);
console.log("Errors: " + report.errors);
// Future: Send CRITICAL alert to Slack #ops
// Future: Retry mechanism
return [{ json: { ...report, alertLevel: "CRITICAL", notified: false, channel: "#ops (pending Slack)" } }];
